text:
Top 15 Recipient Countries


Code
clg_dev |&gt;
  filter(!is.na(Amount_Constant_USD_2023)) |&gt;
  group_by(Country_of_Activity) |&gt;
  summarise(amount = sum(Amount_Constant_USD_2023, na.rm = TRUE) / 1e9,
            n = n()) |&gt;
  slice_max(amount, n = 15) |&gt;
  ggplot(aes(x = reorder(Country_of_Activity, amount), y = amount)) +
  geom_col(fill = "#2c7bb6") +
  coord_flip() +
  scale_y_continuous(labels = label_dollar(suffix = "B")) +
  labs(x = NULL, y = "Constant 2023 USD", title = "Top 15 Recipients") +
  theme_minimal()
